// Grab all the rows returned from your Supabase 'Search/Get' node
const items = $input.all();
const groupedCustomers = {};

// Fungsi kecil agar aman jika Supabase me-return JSON sebagai string
const safeParseJSON = (data) => {
  if (!data) return [];
  if (typeof data === 'string') {
    try { return JSON.parse(data); } catch (e) { return []; }
  }
  return data;
};

// Loop through every single row from Supabase
for (const item of items) {
  const row = item.json;

  // Make sure this matches your customer ID column name exactly
  const custId = row.customerId || row.customer_name || row.customer_id; 

  // 1. If we haven't seen this customer yet, create their base object
  if (!groupedCustomers[custId]) {
    groupedCustomers[custId] = {
      customerId: custId,
      historicalMonths: row.historical_months || 1, // <-- TAMBAHAN DARI V3

      currentPerformance: {
        nettSales: row.nettsales || row.nett_sales, // Handle kemungkinan beda underscore
        currentQty: row.current_qty,
        currentGmPct: row.current_gm_pct,
        status: row.status
      },
      projectedPerformance: {
        projectedSales: row.projected_sales,
        projectedQty: row.projected_qty,
        projectedGmPct: row.projected_gm_pct,
        targetGmPct: row.target_gm_pct || 9.0,      // <-- TAMBAHAN DARI V3
        improvement: row.improvement
      },
      productMixStrategy: {
        // Tarik array JSONB dari database, fallback ke array kosong jika tidak ada
        reduceOrRenegotiate: safeParseJSON(row.reduce_or_renegotiate), // <-- TAMBAHAN DARI V3
        upsellExisting: safeParseJSON(row.upsell_existing),            // <-- TAMBAHAN DARI V3
        productDetails: safeParseJSON(row.product_details),            // <-- DATA BUKU BESAR DARI V3

        intraFamilyShifts: [],
        aiReasoning: row.ai_reasoning || row.aiReasoning
      }
    };
  }

  // 2. Check if this row actually contains a shift using YOUR exact column names
  if (row.product_from || row.product_family) { 
    // Opsional: Cek apakah data panah shift ini sudah ada (menghindari duplikasi saat JOIN DB)
    const existingShift = groupedCustomers[custId].productMixStrategy.intraFamilyShifts.find(
      s => s.from === row.product_from && s.to === row.product_to
    );

    if (!existingShift) {
      groupedCustomers[custId].productMixStrategy.intraFamilyShifts.push({
        family: row.product_family,
        from: row.product_from,
        to: row.product_to,

        // Data krusial untuk UI panah di React (Sesuai output Python)
        shifted_qty: row.product_shifted_qty,
        shifted_sales_value: row.product_shifted_sales_value,
        sales_uplift: row.product_sales_uplift,

        // Extra data lama Anda (boleh tetap dimasukkan walau di Python V3 kita ringkas)
        current_sales_value: row.current_sales_value,
        current_qty: row.product_current_qty,
        current_gm_pct: row.product_current_gm_pct,
        target_gm_pct: row.product_target_gm_pct,
        status: row.product_status,
        reason: row.product_ai_reason,
        projected_qty: row.product_projected_qty
      });
    }
  }
}

// Convert our grouped object back into a standard array
const recommendationsArray = Object.values(groupedCustomers);

// SORTING: Mengurutkan dari minus paling besar ke nilai positif berdasarkan current GM%
recommendationsArray.sort((a, b) => {
  return a.currentPerformance.currentGmPct - b.currentPerformance.currentGmPct;
});

// Return the data exactly how the Python Simulator formatted it
return [{
  json: {
    recommendations: recommendationsArray
  }
}];

